#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    // dp[x] = minimum operations to reach x from 1
    vector<int> dp(N + 1, 0);
    // We can fill bottom-up:
    // dp[1] = 0
    // For x from 1 to N-1:
    //   dp[x+1] = min(dp[x+1], dp[x] + 1)
    //   if 2*x <= N: dp[2*x] = min(dp[2*x], dp[x] + 1)
    //   if 3*x <= N: dp[3*x] = min(dp[3*x], dp[x] + 1)

    const int INF = 1e9;
    for (int i = 2; i <= N; ++i) dp[i] = INF;
    dp[1] = 0;

    for (int x = 1; x <= N; ++x) {
        if (dp[x] == INF) continue;
        int nx = x + 1;
        if (nx <= N && dp[nx] > dp[x] + 1) dp[nx] = dp[x] + 1;
        nx = x * 2;
        if (nx <= N && dp[nx] > dp[x] + 1) dp[nx] = dp[x] + 1;
        nx = x * 3;
        if (nx <= N && dp[nx] > dp[x] + 1) dp[nx] = dp[x] + 1;
    }

    cout << dp[N] << '\n';
    return 0;
}
